Create the upload-handler service that manages disk storage, filename sanitization, and multer middleware configuration.

## 1. Install Dependencies

Add `multer` and `@types/multer` to `apps/server`:

```bash
cd apps/server && pnpm add multer && pnpm add -D @types/multer
```

## 2. Create `apps/server/src/services/core/upload-handler.ts`

```typescript
import multer from 'multer';
import path from 'path';
import { randomUUID } from 'crypto';
import fs from 'fs/promises';

/** Sanitize a filename: strip path components, replace unsafe chars. */
function sanitizeFilename(original: string): string {
  const base = path.basename(original);
  const safe = base.replace(/[^a-zA-Z0-9._-]/g, '_');
  return `${randomUUID().slice(0, 8)}-${safe}`;
}

interface UploadConfig {
  maxFileSize: number;
  maxFiles: number;
  allowedTypes: string[];
}

class UploadHandler {
  /** Build the upload directory path for a given cwd. */
  getUploadDir(cwd: string): string {
    return path.join(cwd, '.dork', '.temp', 'uploads');
  }

  /** Ensure the upload directory exists. */
  async ensureUploadDir(cwd: string): Promise<string> {
    const dir = this.getUploadDir(cwd);
    await fs.mkdir(dir, { recursive: true });
    return dir;
  }

  /** Create a multer middleware instance with dynamic config. */
  createMulterMiddleware(cwd: string, config: UploadConfig) {
    const uploadDir = this.getUploadDir(cwd);

    const storage = multer.diskStorage({
      destination: (_req, _file, cb) => {
        fs.mkdir(uploadDir, { recursive: true })
          .then(() => cb(null, uploadDir))
          .catch((err) => cb(err, uploadDir));
      },
      filename: (_req, file, cb) => {
        cb(null, sanitizeFilename(file.originalname));
      },
    });

    return multer({
      storage,
      limits: {
        fileSize: config.maxFileSize,
        files: config.maxFiles,
      },
      fileFilter: (_req, file, cb) => {
        if (config.allowedTypes.includes('*/*')) {
          return cb(null, true);
        }
        if (config.allowedTypes.includes(file.mimetype)) {
          return cb(null, true);
        }
        cb(new Error(`File type not allowed: ${file.mimetype}`));
      },
    });
  }
}

export const uploadHandler = new UploadHandler();
```

Key design decisions:
- `sanitizeFilename` strips all path components via `path.basename()`, replaces unsafe characters with `_`, and prepends an 8-char UUID prefix to prevent filename collisions
- `createMulterMiddleware` accepts dynamic config per-request so different cwd directories can have different upload configs
- The `destination` callback creates the upload directory lazily on first upload, not at server startup
- File filter supports wildcard (`*/*`) for "allow all" and explicit MIME type matching

## 3. Export from Service Index

If `apps/server/src/services/core/` has an index barrel, add the export. Otherwise, the route file will import directly from the module path.

