## 5. Clipboard Paste Support

The `react-dropzone` `useDropzone` hook does NOT handle clipboard paste by default. To support Ctrl+V/Cmd+V paste of images from clipboard, add a paste event handler in the ChatInputContainer or ChatInput. This can be done by adding a `paste` event listener:

```typescript
const handlePaste = useCallback((e: React.ClipboardEvent) => {
  const items = e.clipboardData?.items;
  if (!items) return;

  const files: File[] = [];
  for (const item of items) {
    if (item.kind === 'file') {
      const file = item.getAsFile();
      if (file) files.push(file);
    }
  }

  if (files.length > 0) {
    e.preventDefault();
    onFilesSelected(files);
  }
  // If no files, allow normal text paste
}, [onFilesSelected]);
```

