### Create transformContent Callback

Create a `transformContent` callback that uploads pending files and prepends their paths to the message. This should be defined inside `ChatPanel` and passed to `useChatSession`:

```typescript
const fileTransformContent = useCallback(async (content: string) => {
  // First apply any external transformContent (from props)
  let transformed = transformContent ? await transformContent(content) : content;

  if (!fileUpload.hasPendingFiles) return transformed;

  const paths = await fileUpload.uploadAndGetPaths();
  fileUpload.clearFiles();

  if (paths.length === 0) return transformed;

  // Convert absolute paths to relative paths from cwd
  const cwd = selectedCwd;
  const relativePaths = paths.map((p) => {
    const cwdPrefix = cwd ? cwd + '/' : '';
    return p.startsWith(cwdPrefix) ? p.slice(cwdPrefix.length) : p;
  });

  const fileSection = relativePaths.length === 1
    ? `Please read the following uploaded file:\n- ${relativePaths[0]}`
    : `Please read the following uploaded files:\n${relativePaths.map((p) => `- ${p}`).join('\n')}`;

  return `${fileSection}\n\n${transformed}`;
}, [fileUpload, transformContent, selectedCwd]);
```

